nodes.implementation:
OPENQASM 3.1;
qubit data;
h data;
qubit[2] anc;
cx data, anc[0];
cx anc[0], anc[1];
@leqo.output 0
let out = data;
@leqo.uncompute
if (false) {
    cx anc[0], anc[1];
    cx data, anc[0];
    @leqo.reusable
    let anc_clean = anc;
}

OPENQASM 3.1;
@leqo.input 0
qubit in_data;
qubit[2] work;
cx in_data, work[0];
x work[1];
@leqo.output 0
let out = in_data;
